mapper.select:
/* 로그인 로그 목록 조회 LoginLogDAO.selectLoginLogInf */ SELECT a.LOG_ID , a.CREAT_DT , a.CONECT_MTHD , a.CONECT_IP , a.CONECT_ID , b.USER_NM AS LOGIN_NM FROM COMTNLOGINLOG a LEFT OUTER JOIN V_ROLE_USER b ON a.CONECT_ID = b.USER_ID AND a.COMP_ID = b.COMP_ID WHERE 1 = 1
AND a.CONECT_MTHD LIKE CONCAT('%',#{searchWrd},'%')
AND DATE_FORMAT(a.CREAT_DT, '%Y%m%d') BETWEEN #{searchBgnDe} AND #{searchEndDe}
ORDER BY a.CREAT_DT DESC LIMIT #{firstIndex}, #{recordCountPerPage}

/* 로그인 로그 총건수 LoginLogDAO.selectLoginLogInfCnt */
SELECT COUNT(a.LOG_ID) as cnt FROM COMTNLOGINLOG a LEFT OUTER JOIN V_ROLE_USER b ON a.CONECT_ID = b.USER_ID AND a.COMP_ID = b.COMP_ID WHERE 1 = 1
AND a.CONECT_MTHD LIKE CONCAT('%',#{searchWrd},'%')
AND DATE_FORMAT(a.CREAT_DT, '%Y%m%d') BETWEEN #{searchBgnDe} AND #{searchEndDe}
